        className={`flex items-center gap-2 px-4 py-2 rounded-full border text-xs font-medium transition-all disabled:opacity-50 whitespace-nowrap backdrop-blur-md hover:shadow-[0_0_15px_rgba(255,255,255,0.1)] active:scale-95 ${className ? className : 'bg-white/5 hover:bg-white/10 border-white/10 text-gray-300 hover:text-white'}`}
    >
        {icon}
        {label}
    </button>
);

const HistoryCard: React.FC<{ entry: HistoryEntry }> = ({ entry }) => (
    <div className="opacity-80 hover:opacity-100 transition-opacity duration-500 mb-8 group animate-slide-up">
        <div className="flex justify-end mb-3">
            <div className="bg-white/5 backdrop-blur-lg px-6 py-3 rounded-2xl rounded-br-sm border border-white/10 text-sm text-gray-200 max-w-[85%] shadow-lg">
                {entry.prompt}
            </div>
        </div>
        <div className="bg-black/40 backdrop-blur-xl border border-white/5 rounded-2xl p-8 shadow-2xl relative overflow-hidden">
             <div className="prose prose-invert prose-sm md:prose-base max-w-none text-gray-300">
                <MarkdownRenderer content={entry.output} />
             </div>
        </div>
    </div>
);

const Shunt: React.FC = () => {
    // Simplified State for "Stream" Architecture
    const [inputText, setInputText] = useState('');
    const [history, setHistory] = useState<HistoryEntry[]>([]);
    const [bulletinDocuments, setBulletinDocuments] = useState<any[]>([]);
    const [initialPrompt, setInitialPrompt] = useState('');
    const [showCopied, setShowCopied] = useState(false);

    const { feedback, isLoading: isRTLoading, applyFeedback, discardFeedback } = useRealTimePrompt(inputText, setInputText);

    const { settings } = useSettings();
    const { usage, tierDetails, incrementUsage } = useSubscription();

    // Processor Hook
    const {
        isLoading,
        error,
        outputText,
        handleShunt,
        handleGradeAndIterate
    } = useShuntProcessor({
        inputText,
        setInputText,
        bulletinDocuments,
        setBulletinDocuments,
        history,
        setHistory,
        initialPrompt,
        setInitialPrompt,
        priority: 'Medium', // Auto-set for simplicity
        selectedModel: 'gemini-3-pro-preview', // Always use best model
        settings,
        usage,
        tierDetails,
        incrementUsage
    });

    const scrollRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (scrollRef.current) {
            scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
        }
    }, [outputText, history, isLoading]);

    const handleSubmit = () => {
        if (!inputText.trim()) return;
        // Default "Magic" action if no specific chip is clicked
        handleShunt(ShuntAction.AMPLIFY);
    };

    const handleCopy = () => {
        navigator.clipboard.writeText(outputText);
        setShowCopied(true);
        setTimeout(() => setShowCopied(false), 2000);
    };

    return (
        <div className="flex flex-col h-full relative bg-transparent">

            {/* --- Stream Area (Output) --- */}
            <div ref={scrollRef} className="flex-grow overflow-y-auto p-6 md:p-12 pb-48 custom-scrollbar scroll-smooth">
                <div className="max-w-4xl mx-auto">

                    {/* Zero State / Welcome */}
                    {history.length === 0 && !outputText && !isLoading && (
                        <div className="flex flex-col items-center justify-center h-[60vh] opacity-80 animate-fade-in">
                            <div className="relative w-24 h-24 mb-8">
                                <div className="absolute inset-0 bg-fuchsia-500 blur-3xl opacity-20 rounded-full animate-pulse"></div>
                                <div className="relative w-full h-full rounded-full bg-gradient-to-br from-fuchsia-500/20 to-cyan-500/20 border border-white/10 flex items-center justify-center shadow-2xl">
                                    <SparklesIcon className="w-10 h-10 text-white/90" />
                                </div>
                            </div>
                            <h1 className="text-4xl md:text-5xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-white to-gray-400 mb-4 tracking-tight text-center">
                                Aether Flow
                            </h1>
                            <p className="text-gray-400 text-lg max-w-md text-center leading-relaxed">
                                What are we transmuting today? <br/>
                                <span className="text-sm text-gray-500">Type your intent below, or select a quick action.</span>
                            </p>
                        </div>
                    )}

                    {/* Historical Stream */}
                    {history.map(entry => (
                        <HistoryCard key={entry.id} entry={entry} />
                    ))}

                    {/* Current User Input Echo (during processing) */}
                    {isLoading && inputText && (
                         <div className="flex justify-end mb-8 animate-slide-up">
                            <div className="bg-white/5 backdrop-blur-md px-6 py-3 rounded-2xl rounded-br-sm border border-white/10 text-gray-200 shadow-lg">
                                {inputText}
                            </div>
                        </div>
                    )}

                    {/* Active Result Card */}
                    {(outputText || isLoading) && (
                        <div className="relative animate-slide-up mb-12">
                            {/* Glow Effect */}
                            <div className="absolute -inset-1 bg-gradient-to-r from-fuchsia-500/20 to-cyan-500/20 rounded-3xl blur-xl transition-opacity duration-1000"></div>

                            <div className="relative bg-black/60 backdrop-blur-2xl border border-white/10 rounded-3xl p-8 md:p-12 shadow-2xl">

                                {isLoading ? (
                                    <div className="flex flex-col items-center justify-center py-16 gap-6">
                                        <div className="relative">
                                            <div className="absolute inset-0 bg-fuchsia-500 blur-xl opacity-30 animate-pulse rounded-full"></div>
                                            <Loader className="w-12 h-12 text-fuchsia-400 relative z-10" />
                                        </div>
                                        <span className="text-fuchsia-200/80 text-sm font-medium tracking-[0.2em] uppercase animate-pulse">
                                            Forging Reality...
                                        </span>
                                    </div>
                                ) : (
                                    <>
                                        {error ? (
                                            <div className="text-red-300 p-6 bg-red-900/10 rounded-2xl border border-red-500/20 flex items-center gap-4">
                                                <div className="w-3 h-3 bg-red-500 rounded-full animate-pulse shadow-[0_0_10px_rgba(239,68,68,0.5)]"></div>
                                                <div>
                                                    <p className="font-bold mb-1">Process Interrupted</p>
                                                    <p className="text-sm opacity-80">{error}</p>
                                                </div>
                                            </div>
                                        ) : (
                                            <div className="prose prose-invert prose-p:leading-relaxed prose-headings:font-bold prose-a:text-cyan-400 max-w-none">
                                                <MarkdownRenderer content={outputText} />
                                            </div>
                                        )}

                                        {/* Result Toolbar */}
                                        {!error && (
                                            <div className="flex flex-wrap items-center gap-3 mt-10 pt-8 border-t border-white/5">
                                                <button
                                                    onClick={handleCopy}
                                                    className="flex items-center gap-2 px-5 py-2.5 rounded-full bg-white/5 hover:bg-white/10 border border-white/5 text-xs font-medium text-gray-300 transition-all hover:text-white"
                                                >
                                                    {showCopied ? <CheckIcon className="w-4 h-4 text-green-400" /> : <DocumentDuplicateIcon className="w-4 h-4" />}
                                                    {showCopied ? 'Copied' : 'Copy Output'}
                                                </button>
                                                <div className="flex-grow"></div>
                                                <button 
                                                    onClick={handleGradeAndIterate}
                                                    className="flex items-center gap-2 px-5 py-2.5 rounded-full bg-cyan-500/10 text-cyan-300 hover:bg-cyan-500/20 border border-cyan-500/30 transition-all hover:shadow-[0_0_15px_rgba(34,211,238,0.2)] text-xs font-bold tracking-wide uppercase"
                                                >
                                                    <ArrowPathIcon className="w-4 h-4" />
                                                    Refine Loop
                                                </button>
                                            </div>
                                        )}
                                    </>
                                )}
                            </div>
                        </div>
                    )}
                </div>
            </div>

            {/* --- The Dock / Omnibar --- */}
            <div className="absolute bottom-0 left-0 right-0 p-4 md:p-8 z-30">
                 {/* Gradient Fade for Scroll */}
                <div className="absolute bottom-0 left-0 right-0 h-48 bg-gradient-to-t from-[#050505] via-[#050505]/90 to-transparent pointer-events-none"></div>

                <div className="max-w-3xl mx-auto flex flex-col gap-4 relative">

                    {/* Intent Chips (Contextual Help) */}
                    <div className="flex gap-3 overflow-x-auto pb-2 custom-scrollbar mask-linear px-4 justify-center">
                        {/* Auto-Fix Button: High visibility for common corrections */}
                        <QuickActionChip 
                            label="Auto-Fix" 
                            icon={<BoltIcon className="w-4 h-4 text-white animate-pulse"/>} 
                            onClick={() => handleShunt(ShuntAction.PROOFREAD)} 
                            disabled={isLoading || !inputText}
                            className="bg-gradient-to-r from-fuchsia-600 to-purple-600 text-white border-transparent hover:from-fuchsia-500 hover:to-purple-500 shadow-lg hover:shadow-fuchsia-500/30"
                        />
                        <QuickActionChip label="Amplify" icon={<SparklesIcon className="w-4 h-4 text-fuchsia-400"/>} onClick={() => handleShunt(ShuntAction.AMPLIFY)} disabled={isLoading || !inputText} />
                        <QuickActionChip label="Summarize" icon={<BrainIcon className="w-4 h-4 text-cyan-400"/>} onClick={() => handleShunt(ShuntAction.SUMMARIZE)} disabled={isLoading || !inputText} />
                        <QuickActionChip label="Fix Grammar" icon={<EditIcon className="w-4 h-4 text-green-400"/>} onClick={() => handleShunt(ShuntAction.PROOFREAD)} disabled={isLoading || !inputText} />
                        <QuickActionChip label="Explain (ELI5)" icon={<BrainIcon className="w-4 h-4 text-yellow-400"/>} onClick={() => handleShunt(ShuntAction.EXPLAIN_LIKE_IM_FIVE)} disabled={isLoading || !inputText} />
                        <QuickActionChip label="Code Plan" icon={<BoltIcon className="w-4 h-4 text-blue-400"/>} onClick={() => handleShunt(ShuntAction.MAKE_ACTIONABLE)} disabled={isLoading || !inputText} />
                    </div>

                    <RealTimeFeedback 
                        isLoading={isRTLoading} 
                        feedback={feedback} 
                        onApply={applyFeedback} 
                        onDiscard={discardFeedback} 
                    />

                    {/* The Omnibar */}
                    <div className="relative group">
                        {/* Glowing Border Effect */}
                        <div className="absolute -inset-0.5 bg-gradient-to-r from-fuchsia-500 to-cyan-500 rounded-2xl opacity-20 group-focus-within:opacity-70 transition duration-500 blur-md group-focus-within:blur-lg"></div>

                        <div className="relative flex items-end gap-3 bg-[#080808] backdrop-blur-xl border border-white/10 rounded-2xl p-3 shadow-2xl">
                            <textarea
                                value={inputText}
                                onChange={(e) => setInputText(e.target.value)}
                                placeholder="Type, paste, or describe your intent..."
                                className="w-full bg-transparent text-gray-100 placeholder-gray-600 text-lg p-3 max-h-48 min-h-[3.5rem] resize-none focus:outline-none custom-scrollbar leading-relaxed"
                                disabled={isLoading}
                                onKeyDown={(e) => { if(e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSubmit(); }}}
                            />
                            <button
                                onClick={handleSubmit}
                                disabled={isLoading || !inputText.trim()}
                                className={`
                                    mb-1 p-3.5 rounded-xl transition-all duration-300 shadow-lg flex-shrink-0
                                    ${isLoading || !inputText.trim() 
                                        ? 'bg-gray-800 text-gray-600 cursor-not-allowed' 
                                        : 'bg-white text-black hover:scale-105 hover:shadow-[0_0_20px_rgba(255,255,255,0.3)]'
                                    }
                                `}
                            >
                                {isLoading ? <Loader className="w-6 h-6" /> : <PaperAirplaneIcon className="w-6 h-6 transform -rotate-45 translate-x-0.5 translate-y-0.5" />}
                            </button>
                        </div>
                    </div>

                    <div className="text-center">
                        <p className="text-[10px] text-gray-600 uppercase tracking-[0.2em] font-medium opacity-50">Powered by Gemini 3 Pro Preview</p>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Shunt;

// services/miaService.ts
import { GoogleGenAI, GenerateContentResponse, Type } from "@google/genai";
import { GeminiResponse, TokenUsage } from '../types';
import { logFrontendError, ErrorSeverity } from "../utils/errorLogger";
import { withRetries } from './apiUtils';

const mapTokenUsage = (response: GenerateContentResponse, model: string): TokenUsage => {
    return {
        prompt_tokens: response.usageMetadata?.promptTokenCount ?? 0,
        completion_tokens: response.usageMetadata?.candidatesTokenCount ?? 0,
        total_tokens: response.usageMetadata?.totalTokenCount ?? 0,
        model: model,
    };
};

export const getMiaChatResponse = async (history: { role: string, parts: { text: string }[] }[], newMessage: string): Promise<string> => {
    try {
        const apiCall = async () => {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
            const chat = ai.chats.create({
                model: 'gemini-3-pro-preview',
                config: {
                    systemInstruction: "You are Mia, a friendly and highly intelligent AI assistant embedded in a complex web application for developers. Be helpful and concise. Your primary role is to assist the user with understanding and operating the application.",
                    // thinkingConfig removed as it is not supported on gemini-3-pro-preview
                },
                history,
            });
            const response = await chat.sendMessage({ message: newMessage });
            return response.text;
        };
        return await withRetries(apiCall);
    } catch (error) {
        logFrontendError(error, ErrorSeverity.High, { context: 'getMiaChatResponse Gemini API call' });
        throw error;
    }
};

export const getMiaErrorAnalysis = async (errorLog: Record<string, any>): Promise<string> => {
    const prompt = `You are an expert software engineer and helpful AI assistant named Mia. You are embedded within a web application. Your task is to analyze the following error report that was just captured from the application. Your analysis should be clear, concise, and helpful to the developer using the application. Structure your response in Markdown.

1.  **Explain the Error:** In simple terms, what does this error mean?
2.  **Identify the Likely Cause:** Based on the stack trace and provided context, what is the most probable reason for this error? Point to specific files or components if possible.
3.  **Suggest a Solution:** Provide concrete, actionable steps the developer can take to fix the issue. If possible, suggest specific code changes.

Here is the error report:
---
${JSON.stringify(errorLog, null, 2)}
---`;
    try {
        const apiCall = async () => {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
            const response = await ai.models.generateContent({
                model: 'gemini-3-pro-preview',
                contents: prompt,
                // thinkingConfig removed as it is not supported on gemini-3-pro-preview
            });
            return response.text;
        };
        return await withRetries(apiCall);
    } catch (error) {
        logFrontendError(error, ErrorSeverity.Critical, { context: 'getMiaErrorAnalysis Gemini API call' });
        throw error;
    }
};

export const generateCodeFixPlan = async (errorLog: Record<string, any>, projectContext: string): Promise<GeminiResponse> => {
  const prompt = `
You are the **Host Agent**, a master orchestrator AI powered by Gemini. Your purpose is to resolve a critical error within the web application by assembling and directing a team of specialist sub-agents.

**Objective:** Initiate a **verifiably validated solutions fix**. The proposed solution must be rigorously analyzed to ensure it effectively resolves the issue without introducing regressions.

**Your Sub-Agent Team:**

1.  **React Sub-Agent:** An expert in the React 19 ecosystem. It analyzes component lifecycle, state management (Hooks), props, JSX, and event handling.
2.  **TypeScript Sub-Agent:** A specialist in static typing. It scrutinizes type definitions, interfaces, Zod schemas, and potential type mismatches.
3.  **DevOps Sub-Agent:** A systems expert. It reviews build configurations, dependencies (package.json), environment variables, and backend API contracts.

**Your Mission:**

Given the following error report and project context, you must perform a collaborative diagnosis and generate a complete, production-quality code fix.

**Execution Protocol:**

1.  **Internal Monologue (Simulated):**
    *   **Host Analysis:** Briefly state your initial assessment of the error.
    *   **Delegate & Synthesize:** For each sub-agent, simulate their analysis process. Write down what each agent would look for and what conclusions they would draw based on the provided error and context.
    *   **Final Strategy:** Based on the synthesized findings from your agents, formulate the definitive root cause and the precise strategy for the fix.

2.  **Generate Implementation Plan:**
    *   Translate your final strategy into a series of \`implementationTasks\`.
    *   For each file that needs modification, you **MUST** provide the **ENTIRE, NEW, and COMPLETE file content** in the 'newContent' field.
    *   Do not provide diffs, partial code, or explanations in the 'newContent' field. It must be only the raw code for the complete file.
    *   Ensure file paths are correct and the generated code is syntactically perfect.

3.  **Output:**
    *   Return your response strictly according to the provided JSON schema.
    *   You are not required to provide clarifying questions, an architectural proposal, or test cases. Return empty arrays or empty strings for those fields.

---
**Error Report:**
\`\`\`json
${JSON.stringify(errorLog, null, 2)}
\`\`\`
---
**Project Context:**
\`\`\`markdown
${projectContext}
\`\`\`
---
`;
    const implementationTaskSchema = {
        type: Type.OBJECT,
        properties: {
            filePath: { type: Type.STRING, description: "The full path to the file that needs to be modified." },
            description: { type: Type.STRING, description: "A one-sentence description of the change." },
            details: { type: Type.STRING, description: "Precise, step-by-step details for a coding AI to follow. Use for descriptive plans." },
            newContent: { type: Type.STRING, description: "The full, complete new content for the file. Use for direct code fixes." },
        },
        required: ['filePath', 'description']
    };

    const responseSchema = {
    type: Type.OBJECT,
    properties: {
        clarifyingQuestions: { type: Type.ARRAY, items: { type: Type.STRING } },
        architecturalProposal: { type: Type.STRING },
        implementationTasks: {
            type: Type.ARRAY,
            items: {
                ...implementationTaskSchema,
                required: ['filePath', 'description', 'newContent'], // newContent is now required for this operation
            },
            description: "A list of files to modify with their full new content."
        },
        testCases: { type: Type.ARRAY, items: { type: Type.STRING } },
        internalMonologue: { 
            type: Type.STRING, 
            description: "The simulated internal monologue of the agent swarm as they collaborate to find a solution." 
        }
    },
    required: ['implementationTasks']
  };

  try {
    const apiCall = async () => {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const model = 'gemini-3-pro-preview';
        const response = await ai.models.generateContent({
            model,
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema,
                // thinkingConfig removed as it is not supported on gemini-3-pro-preview
            },
        });

        if (response.candidates?.[0]?.finishReason === 'MAX_TOKENS') {
            throw new Error("The AI's response was too long and was truncated, resulting in an incomplete code fix plan.");
        }

        const tokenUsage = mapTokenUsage(response, model);
        const jsonText = response.text.trim().replace(/^```(json)?\s*/, '').replace(/```\s*$/, '');
        const parsedResponse = JSON.parse(jsonText);

        return {
            clarifyingQuestions: [],
            architecturalProposal: '',
            testCases: [],
            ...parsedResponse,
            tokenUsage,
        };
    };
    return await withRetries(apiCall);
  } catch (error) {
    logFrontendError(error, ErrorSeverity.Critical, { context: 'generateCodeFixPlan Gemini API call' });
    throw new Error('Failed to generate the code fix. The AI may have returned an invalid response or malformed JSON.');
  }
};
